mapper.update:
UPDATE prescription
SET prescription_status = #{prescriptionStatus},
    total_amount = #{totalAmount}
WHERE id = #{id}

mapper.select:
SELECT p.id AS id, p.prescription_no AS prescriptionNo, d.dept_name AS deptName, e.realname AS doctorName, pat.real_name AS patientName, p.prescription_status AS status, p.total_amount AS totalAmount, p.creation_time AS creationTime FROM prescription p LEFT JOIN register r ON p.register_id = r.id LEFT JOIN department d ON r.deptment_id = d.id LEFT JOIN employee e ON p.doctor_id = e.id LEFT JOIN patient pat ON r.patient_id = pat.id WHERE r.patient_id = #{patientId}
AND p.prescription_status = #{status}
ORDER BY p.creation_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM prescription p
LEFT JOIN register r ON p.register_id = r.id
WHERE r.patient_id = #{patientId}

    AND p.prescription_status = #{status}

SELECT p.register_id AS registerId, 'DRUG' AS itemType, '药品费' AS itemName, p.id AS itemId, p.total_amount AS amount, p.prescription_status AS orderState, d.dept_name AS deptName, r.visit_date AS visitDate, p.creation_time AS createTime, p.dispense_time AS payTime FROM prescription p LEFT JOIN register r ON p.register_id = r.id LEFT JOIN department d ON r.deptment_id = d.id WHERE r.patient_id = #{patientId} AND p.total_amount IS NOT NULL AND p.total_amount > 0
AND p.prescription_status = #{orderState}
ORDER BY p.creation_time DESC LIMIT #{limit} OFFSET #{offset}
